mapper.select:
select c.id, c.content_id as contentId, c.user_id as userId, c.parent_id as parentId, c.comment_text as commentText, c.is_top as isTop, c.create_time as createTime, u.username as username, u.nickname as nickname, u.avatar as avatar, u.role_id as roleId from `comment` c left join sys_user u on c.user_id = u.id where c.status = 1 and c.parent_id in
#{id}
order by c.is_top desc, c.create_time asc, c.id asc
